function solve(nums) {
    const N = nums.length;

    // 1. Find the peak index P
    // The peak is the last index i such that nums[i] < nums[i+1]
    let P = 0;
    for (let i = 0; i < N - 1; i++) {
        if (nums[i] < nums[i+1]) {
            P = i + 1;
        } else {
            // Since the array is unimodal, once it starts decreasing (nums[i] > nums[i+1]), 
            // the peak is i. If we hit equality, it violates strict unimodality, 
            // but based on strict definition, we break here.
            break;
        }
    }

    // 2. Calculate Increasing Sum (S_inc): nums[0] to nums[P]
    let S_inc = 0;
    for (let i = 0; i <= P; i++) {
        S_inc += nums[i];
    }

    // 3. Calculate Decreasing Sum (S_dec): nums[P] to nums[N-1]
    let S_dec = 0;
    for (let i = P; i < N; i++) {
        S_dec += nums[i];
    }

    // 4. Comparison
    if (S_inc > S_dec) {
        return 0;
    } else if (S_dec > S_inc) {
        return 1;
    } else {
        return -1;
    }
}

